  ('social-worker-moex-08079', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童虐待或疏忽的事件常在媒體上被報導出來。被報導出來的個案數都只反映真實面的一小部分。下列那 一個陳述是正確的？', '["疏忽與虐待相比對孩子的傷害較輕微", "兒童虐待只是偶而發生一次而已", "兒童虐待僅會在低社經地位的家庭出現", "一個兒童虐待案件可能出現多種虐待類型"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
